content = r'''#include "Ast2Asg.hpp"
#include <unordered_map>

#define self (*this)

namespace asg {

struct Ast2Asg::Symtbl : public std::unordered_map<std::string, Decl*>
{
  Ast2Asg& m;
  Symtbl* mPrev;
  Symtbl(Ast2Asg& m) : m(m), mPrev(m.mSymtbl) { m.mSymtbl = this; }
  ~Symtbl() { m.mSymtbl = mPrev; }
  Decl* resolve(const std::string& name);
};

Decl* Ast2Asg::Symtbl::resolve(const std::string& name)
{
  auto iter = find(name);
  if (iter != end()) return iter->second;
  ASSERT(mPrev != nullptr);
  return mPrev->resolve(name);
}

TranslationUnit*
Ast2Asg::operator()(ast::TranslationUnitContext* ctx)
{
  auto ret = make<TranslationUnit>();
  if (ctx == nullptr) return ret;
  Symtbl localDecls(self);
  for (auto&& i : ctx->externalDeclaration()) {
    if (auto p = i->declaration()) {
      auto decls = self(p);
      ret->decls.insert(ret->decls.end(), decls.begin(), decls.end());
    } else if (auto p = i->functionDefinition()) {
      auto funcDecl = self(p);
      ret->decls.push_back(funcDecl);
      localDecls[funcDecl->name] = funcDecl;
    } else ABORT();
  }
  return ret;
}

Ast2Asg::SpecQual
Ast2Asg::operator()(ast::DeclarationSpecifiersContext* ctx)
{
  SpecQual ret = { Type::Spec::kINVALID, Type::Qual() };
  for (auto&& i : ctx->declarationSpecifier()) {
    if (auto p = i->typeSpecifier()) {
      if (ret.first == Type::Spec::kINVALID) {
        if (p->Int()) ret.first = Type::Spec::kInt;
        else if (p->Char()) ret.first = Type::Spec::kChar;
        else if (p->Void()) ret.first = Type::Spec::kVoid;
        else ABORT();
      } else ABORT();
    } else if (auto q = i->typeQualifier()) {
      if (q->Const()) ret.second.const_ = true;
      else ABORT();
    } else ABORT();
  }
  return ret;
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DeclaratorContext* ctx, TypeExpr* sub)
{
  return self(ctx->directDeclarator(), sub);
}

static int eval_arrlen(Expr* expr) {
  if (auto p = expr->dcst<IntegerLiteral>()) return p->val;
  if (auto p = expr->dcst<DeclRefExpr>()) {
    auto var = p->decl->dcst<VarDecl>();
    if (!var || !var->type->qual.const_) ABORT();
    return eval_arrlen(var->init);
  }
  if (auto p = expr->dcst<UnaryExpr>()) {
    auto s = eval_arrlen(p->sub);
    if (p->op == UnaryExpr::kPos) return s;
    if (p->op == UnaryExpr::kNeg) return -s;
    ABORT();
  }
  if (auto p = expr->dcst<BinaryExpr>()) {
    if (p->op == BinaryExpr::kAdd) return eval_arrlen(p->lft) + eval_arrlen(p->rht);
    if (p->op == BinaryExpr::kSub) return eval_arrlen(p->lft) - eval_arrlen(p->rht);
    ABORT();
  }
  if (auto p = expr->dcst<InitListExpr>()) {
    if (p->list.empty()) return 0;
    return eval_arrlen(p->list[0]);
  }
  ABORT();
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DirectDeclaratorContext* ctx, TypeExpr* sub)
{
  if (auto p = ctx->Identifier()) return { sub, p->getText() };
  if (ctx->LeftBracket()) {
    auto arrayType = make<ArrayType>();
    arrayType->sub = sub;
    arrayType->len = ctx->assignmentExpression()
      ? eval_arrlen(self(ctx->assignmentExpression()))
      : ArrayType::kUnLen;
    return self(ctx->directDeclarator(), arrayType);
  }
  if (ctx->LeftParen()) {
    auto funcType = make<FunctionType>();
    funcType->sub = sub;
    ret = { funcType, "" };
    return ret;
  }
  ABORT();
}

Expr*
Ast2Asg::operator()(ast::ExpressionContext* ctx)
{
  auto list = ctx->assignmentExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kComma; node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
{
  if (auto p = ctx->logicalOrExpression()) return self(p);
  auto ret = make<BinaryExpr>();
  ret->op = ret->kAssign;
  ret->lft = self(ctx->unaryExpression());
  ret->rht = self(ctx->assignmentExpression());
  return ret;
}

Expr*
Ast2Asg::operator()(ast::LogicalOrExpressionContext* ctx)
{
  auto list = ctx->logicalAndExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kOr; node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::LogicalAndExpressionContext* ctx)
{
  auto list = ctx->equalityExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kAnd; node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::EqualityExpressionContext* ctx)
{
  auto list = ctx->relationalExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    int op = ast::EqualEqual;
    if (auto tn = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1]))
      op = tn->getSymbol()->getType();
    if (op == ast::EqualEqual) node->op = node->kEq;
    else if (op == ast::NotEqual) node->op = node->kNe;
    else ABORT();
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::RelationalExpressionContext* ctx)
{
  auto list = ctx->additiveExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    int op = ast::Less;
    if (auto tn = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1]))
      op = tn->getSymbol()->getType();
    switch (op) {
      case ast::Less: node->op = node->kLt; break;
      case ast::Greater: node->op = node->kGt; break;
      case ast::LessEqual: node->op = node->kLe; break;
      case ast::GreaterEqual: node->op = node->kGe; break;
      default: ABORT();
    }
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
{
  auto list = ctx->multiplicativeExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    int op = ast::Plus;
    if (auto tn = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1]))
      op = tn->getSymbol()->getType();
    if (op == ast::Plus) node->op = node->kAdd;
    else if (op == ast::Minus) node->op = node->kSub;
    else ABORT();
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::MultiplicativeExpressionContext* ctx)
{
  auto list = ctx->unaryExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    int op = ast::Star;
    if (auto tn = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1]))
      op = tn->getSymbol()->getType();
    switch (op) {
      case ast::Star: node->op = node->kMul; break;
      case ast::Slash: node->op = node->kDiv; break;
      case ast::Percent: node->op = node->kMod; break;
      default: ABORT();
    }
    node->lft = ret; node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::UnaryExpressionContexteContext* ctx)
{
  if (auto p = ctx->postfixExpression()) return self(p);
  auto ret = make<UnaryExpr>();
  if (auto op = ctx->unaryOperator()) {
    int t = dynamic_cast<antlr4::tree::TerminalNode*>(op->children[0])
      ->getSymbol()->getType();
    if (t == ast::Plus) ret->op = ret->kPos;
    else if (t == ast::Minus) ret->op = ret->kNeg;
    else if (t == ast::Not) ret->op = ret->kNot;
    ret->sub = self(ctx->unaryExpression());
    return ret;
  }
  ABORT();
}

Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  auto sub = self(ctx->primaryExpression());
  for (unsigned i = 1; i < ctx->children.size(); ++i) {
    if (auto tn = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i])) {
      int type = tn->getSymbol()->getType();
      if (type == ast::LeftParen) {
        auto call = make<CallExpr>();
        call->head = sub;
        if (++i < ctx->children.size()) {
          if (auto arg = dynamic_cast<ast::ArgumentExpressionListContext*>(ctx->children[i])) {
            for (auto e : arg->assignmentExpression())
              call->args.push_back(self(e));
            i++;
          }
        }
        sub = call;
      } else if (type == ast::LeftBracket) {
        auto idx = make<BinaryExpr>();
        idx->op = idx->kIndex; idx->lft = sub;
        if (++i < ctx->children.size())
          idx->rht = self(dynamic_cast<ast::ExpressionContext*>(unctuation*>(ctx->children[i]));
        i++;
        sub = idx;
      }
    }
  }
  return sub;
}

Expr*
Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
{
  if (auto p = ctx->Identifier()) {
    auto ret = make<DeclRefExpr>();
    ret->decl = mSymtbl->resolve(p->getText());
    return ret;
  }
  if (auto p = ctx->Constant()) {
    auto text = p->getText();
    auto ret = make<IntegerLiteral>();
    if (text[0] != '0') ret->val = std::stoll(text);
    else if (text.size() == 1) ret->val = 0;
    else if (text[1] == 'x' || text[1] == 'X')
      ret->val = std::stoll(text.substr(2), nullptr, 16);
    else ret->val = std::stoll(text.substr(1), nullptr, 8);
    return ret;
  }
  if (auto p = ctx->expression()) {
    auto ret = make<ParenExpr>();
    ret->sub = self(p);
    return ret;
  }
  ABORT();
}

Expr*
Ast2Asg::operator()(ast::InitializerContext* ctx)
{
  if (auto p = ctx->assignmentExpression()) return self(p);
  auto ret = make<InitListExpr>();
  if (auto p = ctx->initializerList())
    for (auto&& i : p->initializer()) {
      auto e = self(i);
      if (auto ie = e->dcst<InitListExpr>())
        for (auto s : ie->list) ret->list.push_back(s);
      else ret->list.push_back(e);
    }
  return ret;
}

Stmt*
Ast2Asg::operator()(ast::StatementContext* ctx)
{
  if (auto p = ctx->compoundStatement()) return self(p);
  if (auto p = ctx->expressionStatement()) return self(p);
  if (auto p = ctx->jumpStatement()) return self(p);
  if (auto p = ctx->selectionStatement()) return self(p);
  if (auto p = ctx->iterationStatement()) return self(p);
  ABORT();
}

CompoundStmt*
Ast2Asg::operator()(ast::CompoundStatementContext* ctx)
{
  auto ret = make<CompoundStmt>();
  if (auto p = ctx->blockItemList()) {
    Symtbl localDecls(self);
    for (auto&& i : p->blockItem()) {
      if (auto q = i->declaration()) {
        auto sub = make<DeclStmt>();
        sub->decls = self(q);
        ret->subs.push_back(sub);
      } else if (auto q i->statement())
        ret->subs.push_back(self(q));
      else ABORT();
    }
  }
  return ret;
}

Stmt*
Ast2Asg::operator()(ast::ExpressionStatementContext* ctx)
{
  if (auto p = ctx->expression()) {
    auto ret = make<ExprStmt>();
    ret->expr = self(p);
    return ret;
  }
  return make<NullStmt>();
}

Stmt*
Ast2Asg::operator()(ast::JumpStatementContext* ctx)
{
  if (ctx->Return()) {
    auto ret = make<ReturnStmt>();
    ret->func = mCurrentFunc;
    if (auto p = ctx->expression()) ret->expr = self(p);
    return ret;
  }
  if (ctx->Break()) return make<BreakStmt>();
  if (ctx->Continue()) return make<ContinueStmt>();
  ABORT();
}

Stmt*
Ast2Asg::operator()(ast::SelectionStatementContext* ctx)
{
  auto ret = make<IfStmt>();
  ret->cond = self(ctx->expression());
  ret->then = self(ctx->statement(0));
  if (ctx->Else()) ret->else_ = self(ctx->statement(1));
  return ret;
}

Stmt*
Ast2Asg::operator()(ast::IterationStatementContext* ctx)
{
  if (ctx->While()) {
    auto ret = make<WhileStmt>();
    ret->cond = self(ctx->expression());
    ret->body = self(ctx->statement());
    return ret;
  }
  if (ctx->Do()) {
    auto ret = make<DoStmt>();
    ret->body = self(ctx->statement());
    ret->cond = self(static_cast<ast::ExpressionContext*>(
      ctx->children[ctx->children.size() - 2]));
    return ret;
  }
  ABORT();
}

std::vector<Decl*>
Ast2Asg::operator()(ast::DeclarationContext* ctx)
{
  std::vector<Decl*> ret;
  auto specs = self(ctx->declarationSpecifiers());
  if (auto p = ctx->initDeclaratorList())
    for (auto&& j : p->initDeclarator())
      ret.push_back(self(j, specs));
  return ret;
}

FunctionDecl*
Ast2Asg::operator()(ast::FunctionDefinitionContext* ctx)
{
  auto ret = makeFunctionDecl>();
  mCurrentFunc = ret;
  auto type = make<Type>();
  ret->type = type;
  auto sq = self(ctx->declarationSpecifiers());
  type->spec = sq.first; type->qual = sq.second;
  auto [texp, name] = self(ctx->declarator(), nullptr);
  auto funcType = make<FunctionType>();
  funcType->sub = texp;
  type->texp = funcType;
  ret->name = std::move(name);
  Symtbl localDecls(self);
  (*mSymtbl)[ret->name] = ret;
  ret->body = self(ctx->compoundStatement());
  return ret;
}

Decl*
Ast2Asg::operator()(ast::InitDeclaratorContext* ctx, SpecQual sq)
{
  auto [texp, name] = self(ctx->declarator(), nullptr);
  Decl* ret;
  if (texp->dcst<FunctionType>()) {
    auto fdecl = make<FunctionDecl>();
    auto type = make<Type>();
    fdecl->type = type;
    type->spec = sq.first; type->qual = sq.second; type->texp = texp;
    fdecl->name = std::move(name);
    if (ctx->initializer()) ABORT();
    fdecl->body = nullptr;
    ret = fdecl;
  } else {
    auto vdecl = make<VarDecl>();
    auto type = make<Type>();
    vdecl->type = type;
    type->spec = sq.first; type->qual = sq.second; type->texp = texp;
    vdecl->name = std::move(name);
    vdecl->init = ctx->initializer() ? self(ctx->initializer()) : nullptr;
    ret = vdecl;
  }
  (*mSymtbl)[ret->name] = ret;
  return ret;
}

} // namespace asg
